FUNCTION CreateUserStory(userRole, goal, benefit):
 RETURN "As a " + userRole + ", I want " + goal + 
 " so that " + benefit

// Example usage:
story1 = CreateUserStory("customer", "to save items to cart",
 "I can purchase them later")
PRINT story1
// Output: As a customer, I want to save items to cart 
// so that I can purchase them later
